import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useAuth } from "../context/AuthContext";

function FormAgendamento({ onNovoAgendamento, agendamentoEditando, onFimEdicao }) {
  const { user } = useAuth(); // <-- pega role e id do usuário logado

  // Tipo de atendimento: 'Novo', 'Retorno', 'Solicitar'
  const [tipoAtendimento, setTipoAtendimento] = useState('Novo');

  // Pacientes e pesquisa
  const [pacientes, setPacientes] = useState([]);
  const [buscaPaciente, setBuscaPaciente] = useState('');
  const [pacienteId, setPacienteId] = useState('');
  const [nomePaciente, setNomePaciente] = useState('');
  const [telefone, setTelefone] = useState('');
  const [showLista, setShowLista] = useState(false);

  // Listas para selects
  const [disciplinas, setDisciplinas] = useState([]);
  const [alunos, setAlunos] = useState([]);

  // Campos de formulário
  const [disciplinaId, setDisciplinaId] = useState('');
  const [data, setData] = useState('');   // ex: "2025-06-10"
  const [hora, setHora] = useState('19:00'); // ex: "14:30"
  const [observacoes, setObservacoes] = useState('');

  // Operador (obrigatório) e auxiliares (opcionais)
  const [operadorId, setOperadorId] = useState('');
  const [auxiliar1Id, setAuxiliar1Id] = useState('');
  const [auxiliar2Id, setAuxiliar2Id] = useState('');

  // Mensagem de sucesso/erro
  const [mensagem, setMensagem] = useState('');

  // Ref para detectar clique fora da lista de pacientes
  const inputRef = useRef(null);

  // ========== Carrega listas iniciais (pacientes, disciplinas, alunos) ==========
  useEffect(() => {
    // Carregar pacientes
    axios
      .get('/api/pacientes')
      .then(res => setPacientes(res.data))
      .catch(err => console.error('Erro ao buscar pacientes:', err));

    // Carregar disciplinas
    axios
      .get('/api/disciplinas')
      .then(res => setDisciplinas(res.data))
      .catch(err => console.error('Erro ao buscar disciplinas:', err));

    // Carregar alunos apenas se usuário NÃO for “Aluno”
    if (user.role !== 'Aluno') {
      axios
        .get('/api/alunos')
        .then(res => setAlunos(res.data))
        .catch(err => console.error('Erro ao buscar alunos:', err));
    }
  }, [user.role]);

  // ========== Se for “Aluno”, já fixa operadorId = user.id ==========
  useEffect(() => {
    if (user.role === 'Aluno') {
      setOperadorId(user.id.toString());
    }
  }, [user]);

  // ========== Preenche campos quando estivermos editando um agendamento ==========
  useEffect(() => {
    if (agendamentoEditando) {
      // Traduz status para o nosso tipoAtendimento
      const statusEdit = agendamentoEditando.status; // ex: "Solicitado", "Novo", "Retorno"
      setTipoAtendimento(statusEdit === 'Solicitado' ? 'Solicitar' : statusEdit);

      // Disciplina
      setDisciplinaId(String(agendamentoEditando.disciplina_id || ''));

      // Paciente
      setPacienteId(agendamentoEditando.paciente_id || '');
      setNomePaciente(agendamentoEditando.nome_paciente || '');
      setTelefone(agendamentoEditando.telefone || '');
      setBuscaPaciente(
        (agendamentoEditando.nome_paciente || '') +
          (agendamentoEditando.telefone ? ' - ' + agendamentoEditando.telefone : '')
      );
      setShowLista(false);

      // Data e Hora
      if (agendamentoEditando.data_hora) {
        // Supondo que agendamentoEditando.data_hora venha como "2025-06-10T14:30:00.000Z"
        const dt = new Date(agendamentoEditando.data_hora);
        const yyyy = dt.getFullYear();
        const mm = String(dt.getMonth() + 1).padStart(2, '0');
        const dd = String(dt.getDate()).padStart(2, '0');
        const HH = String(dt.getHours()).padStart(2, '0');
        const MM = String(dt.getMinutes()).padStart(2, '0');

        setData(`${yyyy}-${mm}-${dd}`); // formato “YYYY-MM-DD”
        setHora(`${HH}:${MM}`);        // formato “HH:MM”
      }

      setObservacoes(agendamentoEditando.observacoes || '');

      // Operador e auxiliars
      // Se for um “Aluno” fazendo edição, garantimos que operadorId fique fixo
      if (user.role !== 'Aluno') {
        setOperadorId(
          agendamentoEditando.aluno_id
            ? String(agendamentoEditando.aluno_id)
            : agendamentoEditando.operador_id || ''
        );
      }
      setAuxiliar1Id(String(agendamentoEditando.auxiliar1_id || ''));
      setAuxiliar2Id(String(agendamentoEditando.auxiliar2_id || ''));
    } else {
      // Se não estiver editando, limpa tudo
      setTipoAtendimento('Novo');
      setDisciplinaId('');
      setPacienteId('');
      setNomePaciente('');
      setTelefone('');
      setData('');
      setHora('19:00');
      setObservacoes('');
      if (user.role !== 'Aluno') {
        setOperadorId('');
      }
      setAuxiliar1Id('');
      setAuxiliar2Id('');
      setBuscaPaciente('');
      setShowLista(false);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [agendamentoEditando]);

  // ========== Fecha lista de pacientes ao clicar fora ==========
  useEffect(() => {
    const handleClickOutside = event => {
      if (inputRef.current && !inputRef.current.contains(event.target)) {
        setShowLista(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // ========== Filtra pacientes para a pesquisa (nome OU telefone) ==========
  const pacientesFiltrados = pacientes.filter(p => {
    const termo = buscaPaciente.toLowerCase();
    return (
      p.nome.toLowerCase().includes(termo) ||
      (p.telefone && p.telefone.includes(termo))
    );
  });

  // ========== Quando usuário clica em um paciente da lista ==========
  const handleSelecionarPaciente = paciente => {
    setPacienteId(paciente.id);
    setNomePaciente(paciente.nome);
    setTelefone(paciente.telefone || '');
    setBuscaPaciente(
      paciente.nome + (paciente.telefone ? ' - ' + paciente.telefone : '')
    );
    setShowLista(false);
  };

  // ========== Função única de envio do formulário ==========
  const handleSubmit = e => {
    e.preventDefault();
    setMensagem('');

    // Validações:
    if (!disciplinaId) {
      setMensagem('Selecione uma disciplina');
      return;
    }

    if (tipoAtendimento !== 'Solicitar' && !pacienteId) {
      setMensagem('Selecione um paciente');
      return;
    }

    // Operador obrigatoriamente deve existir
    if (!operadorId) {
      setMensagem('Selecione um operador');
      return;
    }

    // Operador e Auxiliar1 não podem ser iguais
    if (auxiliar1Id && operadorId === auxiliar1Id) {
      setMensagem('Operador e auxiliar devem ser alunos diferentes');
      return;
    }
    // Auxiliar1 e Auxiliar2 não podem ser iguais
    if (auxiliar1Id && auxiliar2Id && auxiliar1Id === auxiliar2Id) {
      setMensagem('Auxiliares devem ser alunos diferentes');
      return;
    }
    // Operador e Auxiliar2 não podem ser iguais
    if (auxiliar2Id && operadorId === auxiliar2Id) {
      setMensagem('Operador e auxiliar devem ser alunos diferentes');
      return;
    }

    // Monta o objeto com base nos campos e no tipo de atendimento
    const dados = {
      disciplina_id: disciplinaId,
      // se for “Solicitar”, paciente fica null e recepção cuidará depois
      paciente_id: tipoAtendimento === 'Solicitar' ? null : pacienteId,
      nome_paciente:
        tipoAtendimento === 'Solicitar' ? null : nomePaciente,
      telefone:
        tipoAtendimento === 'Solicitar' ? null : telefone,
      data_hora: `${data}T${hora}:00`, // ex: “2025-06-10T14:30:00”
      observacoes:
        tipoAtendimento === 'Solicitar' ? null : observacoes,
      aluno_id: operadorId,       // no backend, “aluno_id” equivale ao operador
      auxiliar1_id: auxiliar1Id || null,
      auxiliar2_id: auxiliar2Id || null,
      status:
        tipoAtendimento === 'Solicitar'
          ? 'Solicitado'
          : tipoAtendimento,        // “Novo” ou “Retorno”
      solicitado_por_recepcao:
        tipoAtendimento === 'Solicitar',
    };

    // Se estivermos editando, faz PUT; caso contrário, POST
    if (agendamentoEditando) {
      axios
        .put(`/api/agendamentos/${agendamentoEditando.id}`, dados)
        .then(() => {
          setMensagem('Agendamento atualizado com sucesso!');
          onNovoAgendamento && onNovoAgendamento();
          onFimEdicao && onFimEdicao();
        })
        .catch(err => {
          console.error('Erro ao atualizar agendamento:', err);
          setMensagem('Erro ao atualizar agendamento.');
        });
    } else {
      axios
        .post('/api/agendamentos', dados)
        .then(() => {
          setMensagem('Agendamento cadastrado com sucesso!');
          onNovoAgendamento && onNovoAgendamento();
          // Limpa o formulário (exceto operador se for Aluno)
          setDisciplinaId('');
          setPacienteId('');
          setNomePaciente('');
          setTelefone('');
          setData('');
          setHora('19:00');
          setObservacoes('');
          if (user.role !== 'Aluno') {
            setOperadorId('');
          }
          setAuxiliar1Id('');
          setAuxiliar2Id('');
          setBuscaPaciente('');
        })
        .catch(err => {
          console.error('Erro ao cadastrar agendamento:', err);
          setMensagem('Erro ao cadastrar agendamento.');
        });
    }
  };

  // =================== JSX (interface) ===================
  return (
    <div className="bg-white mx-auto max-w-2xl rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">Agendar Paciente</h2>

        {/* ===== Tipo de atendimento ===== */}
        <div className="flex flex-wrap gap-2 mb-6">
          {['Novo', 'Retorno', 'Solicitar'].map(tipo => (
            <button
              key={tipo}
              type="button"
              onClick={() => setTipoAtendimento(tipo)}
              className={`px-4 py-1 rounded-full font-semibold transition
                ${
                  tipoAtendimento === tipo
                    ? 'bg-[#D9E0FF] text-gray-800'
                    : 'bg-gray-200 text-gray-800 hover:bg-gray-300'
                }`}
            >
              {tipo === 'Solicitar' ? 'Solicitar para Recepção' : tipo}
            </button>
          ))}
        </div>

        {/* ===== Disciplina ===== */}
        <div className="mb-6">
          <label className="block mb-1 font-medium">Disciplina</label>
          <div className="flex flex-wrap gap-2">
            {disciplinas.map(d => (
              <button
                key={d.id}
                type="button"
                className={`px-4 py-1 rounded-full border transition ${
                  disciplinaId === String(d.id)
                    ? 'bg-[#D9E0FF] text-gray-800 font-semibold'
                    : 'bg-gray-100 text-gray-800 hover:bg-gray-300'
                }`}
                onClick={() => setDisciplinaId(String(d.id))}
              >
                {d.nome}
              </button>
            ))}
          </div>
          {disciplinaId === '' && (
            <span className="text-red-600 text-xs mt-2 block">
              Selecione uma disciplina
            </span>
          )}
        </div>

        {/* ===== Paciente ===== */}
        {tipoAtendimento !== 'Solicitar' && (
          <div className="mb-6 relative" ref={inputRef}>
            <label className="block mb-1 font-medium">Paciente</label>
            <input
              type="text"
              className="w-full border rounded px-3 py-2"
              placeholder="Digite nome ou telefone para buscar"
              value={buscaPaciente}
              onChange={e => {
                setBuscaPaciente(e.target.value);
                setShowLista(true);
                setPacienteId('');
              }}
              onFocus={() => setShowLista(true)}
              required
            />
            {showLista && buscaPaciente && (
              <ul className="absolute z-10 bg-white border w-full rounded shadow max-h-40 overflow-y-auto">
                {pacientesFiltrados.length > 0 ? (
                  pacientesFiltrados.map(p => (
                    <li
                      key={p.id}
                      className="px-3 py-2 cursor-pointer hover:bg-blue-100"
                      onClick={() => handleSelecionarPaciente(p)}
                    >
                      {p.nome} {p.telefone && `- ${p.telefone}`}
                    </li>
                  ))
                ) : (
                  <li className="px-3 py-2 text-gray-400">
                    Nenhum paciente encontrado
                  </li>
                )}
              </ul>
            )}
            {pacienteId && (
              <div className="mt-2 flex flex-col gap-2">
                <input
                  type="text"
                  className="border rounded px-3 py-2 bg-gray-100"
                  value={nomePaciente}
                  readOnly
                />
                <input
                  type="text"
                  className="border rounded px-3 py-2 bg-gray-100"
                  value={telefone}
                  readOnly
                />
              </div>
            )}
          </div>
        )}

        {/* ===== Data e Hora ===== */}
        <div className="mb-6 flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <label className="block mb-1 font-medium">Data do Atendimento</label>
            <input
              type="date"
              className="w-full border rounded-full px-3 py-2"
              value={data}
              onChange={e => setData(e.target.value)}
              required
            />
          </div>
          <div className="flex-1">
            <label className="block mb-1 font-medium">Hora do Atendimento</label>
            <input
              type="time"
              className="w-full border rounded-full px-3 py-2"
              value={hora}
              onChange={e => setHora(e.target.value)}
              required
            />
          </div>
        </div>

        {/* ===== Operador e Auxiliares ===== */}
        <div className="mb-6">
          <label className="block mb-4 font-medium">
            Alunos que irão realizar o atendimento
          </label>
          <div className="flex flex-col md:flex-row gap-4">
            {/* Operador */}
            <div className="flex-1">
              <label className="block mb-1 text-sm font-semibold">Operador</label>
              {user.role === 'Aluno' ? (
                // Se for Aluno, mostramos o próprio nome fixo e ocultamos o select
                <input
                  type="text"
                  className="w-full border rounded px-3 py-2 bg-gray-100 cursor-not-allowed"
                  value={user.nome}
                  readOnly
                />
              ) : (
                <select
                  required
                  className="w-full border rounded px-3 py-2"
                  value={operadorId}
                  onChange={e => setOperadorId(e.target.value)}
                >
                  <option value="">Nome completo do operador</option>
                  {alunos.map(a => (
                    <option key={a.id} value={a.id}>
                      {a.nome}
                    </option>
                  ))}
                </select>
              )}
            </div>

            {/* Auxiliar 1 */}
            <div className="flex-1 mt-4 md:mt-0">
              <label className="block mb-1 text-sm font-semibold">Auxiliar 1</label>
              <select
                className="w-full border rounded px-3 py-2"
                value={auxiliar1Id}
                onChange={e => setAuxiliar1Id(e.target.value)}
              >
                <option value="">Nome completo do auxiliar</option>
                {alunos.map(a => (
                  // Impedimos que o auxiliar1 seja o mesmo que o operador já selecionado
                  <option
                    key={a.id}
                    value={a.id}
                    disabled={a.id === Number(operadorId)}
                  >
                    {a.nome}
                  </option>
                ))}
              </select>
            </div>

            {/* Auxiliar 2 */}
            <div className="flex-1 mt-4 md:mt-0">
              <label className="block mb-1 text-sm font-semibold">Auxiliar 2</label>
              <select
                className="w-full border rounded px-3 py-2"
                value={auxiliar2Id}
                onChange={e => setAuxiliar2Id(e.target.value)}
              >
                <option value="">Nome completo do auxiliar</option>
                {alunos.map(a => (
                  // Impedimos que o auxiliar2 seja igual a operador ou auxiliar1
                  <option
                    key={a.id}
                    value={a.id}
                    disabled={
                      a.id === Number(operadorId) ||
                      a.id === Number(auxiliar1Id)
                    }
                  >
                    {a.nome}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* ===== Botões de salvar / cancelar ===== */}
        <div className="mt-8 flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#3172C0] hover:bg-[#083A76] text-white font-bold py-2 px-6 rounded-full"
          >
            {tipoAtendimento === 'Solicitar'
              ? 'Solicitar para Recepção'
              : 'Agendar Paciente'}
          </button>

          {agendamentoEditando && (
            <button
              type="button"
              className="bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>

        {mensagem && (
          <p className="mt-4 text-red-600 font-medium">{mensagem}</p>
        )}
      </form>
    </div>
  );
}

export default FormAgendamento;
